from flask import Flask, request, redirect, url_for, session, render_template, flash
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Dummy user database
users_db = {
    'user1': generate_password_hash('password1'),
    'user2': generate_password_hash('password2')
}

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']

        if username in users_db and check_password_hash(users_db[username], password):
            session['username'] = username
            return redirect(url_for('verify_mfa'))
        else:
            flash('Invalid credentials')
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET'])
def verify_mfa():
    if 'username' in session:
        # Simulate MFA verification in background
        from threading import Thread
        mfa_thread = Thread(target=send_mfa_code, args=(session['username'],))
        mfa_thread.start()
        return redirect(url_for('protected'))
    else:
        flash('Unauthorized')
        return redirect(url_for('login'))

def send_mfa_code(username):
    # Simulate MFA code sending logic
    import random
    mfa_code = random.randint(1000, 9999)
    session['mfa_code'] = mfa_code
    print(f"Sending MFA code {mfa_code} to user {username}")

@app.route('/protected', methods=['GET'])
def protected():
    if 'username' in session and 'mfa_code' in session:
        return f"Welcome, {session['username']}! Access granted."
